class Solution(object):
    def countTime(self, time):
        count = 0
        for h in range(24):
            for m in range(60):
                time_str = f"{h:02d}:{m:02d}"
                if all(time_str[i] == time[i] or time[i] == '?' for i in range(5)):
                    count += 1
        return count
